# Definition for singly-linked list.
class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

class Solution:
    def reverseList(self, head: ListNode) -> ListNode:
        prev = None
        curr = head

        while curr:
            next_temp = curr.next   # 暂存下一个节点，防止断链
            curr.next = prev        # 反转指针方向
            prev = curr             # prev 指针前移
            curr = next_temp        # curr 指针前移

        return prev
